changeSet.sql:
-- Вставка тестовых данных в таблицу outbox_events
-- Сначала получим ID из transfers для связывания
DO $$
DECLARE
transfer1_id UUID;
    transfer2_id UUID;
    transfer3_id UUID;
    transfer4_id UUID;
BEGIN
    -- Получаем ID существующих переводов
SELECT id INTO transfer1_id FROM transfers WHERE correlation_id = 'a1b2c3d4-e5f6-7890-abcd-ef1234567890';
SELECT id INTO transfer2_id FROM transfers WHERE correlation_id = 'd4e5f6g7-h8i9-0123-def0-345678901234';
SELECT id INTO transfer3_id FROM transfers WHERE correlation_id = 'f6g7h8i9-j0k1-2345-f012-567890123456';
SELECT id INTO transfer4_id FROM transfers WHERE correlation_id = 'h8i9j0k1-l2m3-4567-1234-789012345678';

-- Вставляем события с полученными ID
INSERT INTO outbox_events (aggregate_type, aggregate_id, event_type, payload, status, created_at) VALUES
                                                                                                      -- Отправленные события
                                                                                                      ('Transfer', transfer1_id, 'DEBIT_REQUEST', '{"accountId": "ACC001", "amount": 1000.00, "currency": "USD"}', 'SENT', '2024-01-15 10:00:01'),
                                                                                                      ('Transfer', transfer1_id, 'CREDIT_REQUEST', '{"accountId": "ACC002", "amount": 1000.00, "currency": "USD"}', 'SENT', '2024-01-15 10:00:05'),

                                                                                                      -- Новые события ожидающие отправки
                                                                                                      ('Transfer', transfer2_id, 'DEBIT_REQUEST', '{"accountId": "ACC004", "amount": 1200.00, "currency": "USD"}', 'NEW', '2024-01-16 09:15:01'),

                                                                                                      -- События для неудачных переводов
                                                                                                      ('Transfer', transfer3_id, 'DEBIT_REQUEST', '{"accountId": "ACC006", "amount": 2000.00, "currency": "USD"}', 'SENT', '2024-01-16 11:45:01'),

                                                                                                      -- События для компенсированных переводов
                                                                                                      ('Transfer', transfer4_id, 'DEBIT_REQUEST', '{"accountId": "ACC008", "amount": 800.00, "currency": "USD"}', 'SENT', '2024-01-16 15:00:01'),
                                                                                                      ('Transfer', transfer4_id, 'CREDIT_REQUEST', '{"accountId": "ACC009", "amount": 800.00, "currency": "USD"}', 'SENT', '2024-01-16 15:00:05'),
                                                                                                      ('Transfer', transfer4_id, 'COMPENSATE_DEBIT', '{"accountId": "ACC008", "amount": 800.00, "currency": "USD"}', 'SENT', '2024-01-16 15:00:10');
END $$;
